import { useMemo } from "react";
import { useAppStore } from "../store/appStore";
import { api as http } from "../uiApiCompat";
import { usePoll } from "../hooks/usePoll";
import { useBacktestResults } from "../contexts/BacktestResultsContext";
import V2EmptyState from "../components/V2EmptyState";

/* -- helpers ------------------------------------------------- */
const usd  = (v) => `$${Math.abs(v).toLocaleString("en-US", { minimumFractionDigits: 0 })}`;
const pct  = (v) => `${v >= 0 ? "+" : ""}${(v * 100).toFixed(2)}%`;
const tone = (v) => (v >= 0 ? "green" : "red");

/* -- stat card ----------------------------------------------- */
function Stat({ label, value, t = "blue", sub = "" }) {
  return (
    <div className="v2-card">
      <div className="v2-ct">{label}</div>
      <div className={`v2-cv v2-${t}`}>{value}</div>
      {sub && <div className="v2-muted" style={{ marginTop: 8 }}>{sub}</div>}
    </div>
  );
}

/* -- main page ----------------------------------------------- */
export default function Risk() {
  const { state } = useAppStore();

  /* poll risk exposure — response shape: { exposure: [{ bot_name, equity, positions_count, positions_value, exposure_pct, buying_power }], total_equity } */
  const { data: exposureData, loading: loadingExp } = usePoll(
    async () => {
      const r = await http.get("/risk/exposure");
      const raw = r.data;
      /* also fetch drawdown for per-bot detail */
      let ddData = {};
      try { const dd = await http.get("/risk/drawdown"); ddData = dd.data || {}; } catch {}
      /* reshape into the structure our UI expects */
      const PAPER_BOTS = new Set(['layla', 'paper', 'demo']);
      const bots = (raw.exposure || []).filter(b => !PAPER_BOTS.has((b.bot_name || '').toLowerCase())).map(b => {
        const ddBot = (ddData.bots || []).find(d => d.bot === b.bot_name) || {};
        return {
          name: b.bot_name,
          long: Math.max(b.positions_value || 0, 0),
          short: 0,
          net: b.positions_value || 0,
          gross: Math.abs(b.positions_value || 0),
          equity: b.equity || 0,
          buying_power: b.buying_power || 0,
          day_pnl: ddBot.day_pnl || 0,
        };
      });
      const totalLong = bots.reduce((a, b) => a + b.long, 0);
      const totalShort = bots.reduce((a, b) => a + b.short, 0);
      const totalNet = bots.reduce((a, b) => a + b.net, 0);
      const totalGross = bots.reduce((a, b) => a + b.gross, 0);
      return {
        bots,
        total: {
          long: totalLong,
          short: totalShort,
          net: totalNet,
          gross: totalGross,
          var: ddData.max_drawdown != null ? Math.abs(ddData.max_drawdown) * (raw.total_equity || 0) : null,
        },
      };
    },
    { intervalMs: 15000, immediate: true, enabled: !state.offlineMode }
  );

  /* backtest results from shared context */
  const { results: btData, loading: loadingBt } = useBacktestResults();

  /* derive stats from backtest data */
  const stats = useMemo(() => {
    if (!btData || typeof btData !== "object") return null;
    const vals = Object.values(btData);
    if (!vals.length) return null;
    const avgSharpe = vals.reduce((a, b) => a + (b.sharpe || 0), 0) / vals.length;
    const worstDD = Math.min(...vals.map(v => v.max_dd || 0));
    return { sharpe: avgSharpe, maxDD: worstDD };
  }, [btData]);

  const exposure = exposureData || {};
  const sharpe = stats?.sharpe ?? null;
  const maxDD = stats?.maxDD ?? null;
  const loading = loadingExp && loadingBt;

  if (loading) {
    return (
      <>
        <div className="v2-pagehead">
          <div>
            <h1 className="v2-h1">Risk Overview</h1>
            <div className="v2-muted">Loading risk data...</div>
          </div>
        </div>
        <div className="v2-grid">
          {[1,2,3,4].map(i => (
            <div key={i} className="v2-card">
              <div className="v2-ct">Loading...</div>
              <div className="v2-cv v2-blue" style={{ opacity: 0.3 }}>--</div>
            </div>
          ))}
        </div>
      </>
    );
  }

  const expData = exposure.bots || [];
  const expTotal = exposure.total || {};

  return (
    <>
      {/* -- header -------------------------------------------- */}
      <div className="v2-pagehead">
        <div>
          <h1 className="v2-h1">Risk Overview</h1>
          <div className="v2-muted">Comprehensive risk dashboard: exposure, drawdown, correlation, and limit monitoring.</div>
        </div>
      </div>

      {/* -- top stats ----------------------------------------- */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <Stat label="Total Exposure (Gross)" value={expTotal.gross ? usd(expTotal.gross) : "--"} t="blue" sub="Long + Short combined" />
        <Stat label="VaR (1d, 95%)" value={expTotal.var ? usd(expTotal.var) : "--"} t="amber" sub="Value at Risk estimate" />
        <Stat label="Max Drawdown" value={maxDD != null ? pct(maxDD) : "--"} t="red" sub="Worst peak-to-trough" />
        <Stat label="Sharpe Ratio" value={sharpe != null ? sharpe.toFixed(2) : "--"} t={sharpe != null && sharpe > 1 ? "green" : "amber"} sub="Risk-adjusted return" />
      </div>

      {/* -- exposure breakdown table -------------------------- */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card wide">
          <div className="v2-ct">Exposure Breakdown by Bot</div>
          {expData.length === 0 ? (
            <V2EmptyState title="No Exposure Data" message="Waiting for live exposure data from the API." />
          ) : (
            <div className="v2-table" style={{ marginTop: 8 }}>
              <div className="v2-thead" style={{ gridTemplateColumns: "120px repeat(4, 1fr) 80px" }}>
                <span>Bot</span>
                <span style={{ textAlign: "right" }}>Long</span>
                <span style={{ textAlign: "right" }}>Short</span>
                <span style={{ textAlign: "right" }}>Net</span>
                <span style={{ textAlign: "right" }}>Gross</span>
                <span style={{ textAlign: "center" }}>Bias</span>
              </div>
              {expData.map(bot => {
                const bias = bot.net > 0 ? "LONG" : bot.net < 0 ? "SHORT" : "FLAT";
                const biasColor = bias === "LONG" ? "green" : bias === "SHORT" ? "red" : "blue";
                return (
                  <div key={bot.name} className="v2-tr" style={{ gridTemplateColumns: "120px repeat(4, 1fr) 80px" }}>
                    <span style={{ fontWeight: 600 }}>{bot.name}</span>
                    <span className="v2-mono v2-green" style={{ textAlign: "right" }}>{usd(bot.long)}</span>
                    <span className="v2-mono v2-red" style={{ textAlign: "right" }}>{usd(bot.short)}</span>
                    <span className={`v2-mono v2-${tone(bot.net)}`} style={{ textAlign: "right" }}>{usd(bot.net)}</span>
                    <span className="v2-mono" style={{ textAlign: "right" }}>{usd(bot.gross)}</span>
                    <span style={{ textAlign: "center" }}>
                      <span className={`v2-pill v2-${biasColor}`} style={{ fontSize: 10 }}>{bias}</span>
                    </span>
                  </div>
                );
              })}
              {/* Total row */}
              {expTotal.long != null && (
                <div className="v2-tr" style={{ gridTemplateColumns: "120px repeat(4, 1fr) 80px", borderTop: "1px solid rgba(255,255,255,0.12)", background: "rgba(255,255,255,0.02)" }}>
                  <span style={{ fontWeight: 800 }}>TOTAL</span>
                  <span className="v2-mono v2-green" style={{ textAlign: "right", fontWeight: 700 }}>{usd(expTotal.long)}</span>
                  <span className="v2-mono v2-red" style={{ textAlign: "right", fontWeight: 700 }}>{usd(expTotal.short)}</span>
                  <span className={`v2-mono v2-${tone(expTotal.net)}`} style={{ textAlign: "right", fontWeight: 700 }}>{usd(expTotal.net)}</span>
                  <span className="v2-mono" style={{ textAlign: "right", fontWeight: 700 }}>{usd(expTotal.gross)}</span>
                  <span style={{ textAlign: "center" }}>
                    <span className={`v2-pill v2-${expTotal.net >= 0 ? "green" : "red"}`} style={{ fontSize: 10 }}>
                      {expTotal.net > 0 ? "LONG" : expTotal.net < 0 ? "SHORT" : "FLAT"}
                    </span>
                  </span>
                </div>
              )}
            </div>
          )}
        </div>
      </div>

      {/* -- position concentration ---------------------------- */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card wide">
          <div className="v2-ct">Position Concentration (Top 10 by Weight)</div>
          <V2EmptyState title="No Position Data" message="Position concentration data will appear when the API provides position-level detail." />
        </div>
      </div>

      {/* -- drawdown chart + correlation warnings ------------- */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card half">
          <div className="v2-ct">Drawdown Curve</div>
          <V2EmptyState title="No Drawdown Data" message="Drawdown curve will render when live drawdown data is available." />
        </div>

        <div className="v2-card half">
          <div className="v2-ct">Correlation Warnings</div>
          <V2EmptyState title="No Correlation Data" message="Correlation warnings will appear when the API provides pair-level data." />
        </div>
      </div>

      {/* -- risk limits status -------------------------------- */}
      <div className="v2-grid">
        <div className="v2-card wide">
          <div className="v2-ct">Risk Limits Status</div>
          <V2EmptyState title="No Risk Limits" message="Risk limit monitoring will activate when limits are configured via the API." />
        </div>
      </div>
    </>
  );
}
